import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../lib/supabaseClient';
import EnquiryForm from './EnquiryForm';

// Fix for "Property 'google' does not exist on type 'Window & typeof globalThis'"
declare global {
  interface Window {
    google: any;
  }
}

// --- TYPE DEFINITIONS ---
interface Vehicle {
  id: string;
  name: string;
  price_per_km_cents: number;
  capacity_seats: number;
  capacity_bags: number;
  hero_image_url: string;
  specs?: any; 
  details?: {
    features: string[];
    idealFor: string[];
  };
}

interface Quote {
  totalPrice: number;
  distanceKm: number;
  durationMinutes: number;
  breakdown: {
    base: number;
    distance: number;
    returnTripSurcharge: number;
    babySeatSurcharge: number;
    trailerSurcharge: number;
    weekendSurcharge: number;
    afterHoursSurcharge: number;
    holidaySurcharge: number;
  };
}

interface VehicleWithQuote {
    vehicle: Vehicle;
    quote: Quote;
}

interface PricingRule {
  rule_type: string;
  value_cents: number;
  days_of_week?: number[];
  start_time?: string;
  end_time?: string;
}

interface BookingDashboardProps {
  initialData?: {
    pickup?: { address: string; placeId: string; lat: number; lng: number };
    dropoff?: { address: string; placeId: string; lat: number; lng: number };
    date?: string;
    time?: string;
    passengers?: number;
    vehicleId?: string;
  } | null;
}

const JOBURG_BOUNDS = { south: -26.35, west: 27.85, north: -26.05, east: 28.25 };

// --- MAIN COMPONENT ---
const BookingDashboard: React.FC<BookingDashboardProps> = ({ initialData }) => {
  // Component State
  const [currentStep, setCurrentStep] = useState(1); // 1=Ride, 2=Vehicle, 3=Details, 4=Payment, 5=Success, 6=Enquiry
  const [showEnquiry, setShowEnquiry] = useState(false);

  const [vehicles, setVehicles] = useState<Vehicle[]>([]);
  const [pricingRules, setPricingRules] = useState<PricingRule[]>([]);
  const [publicHolidays, setPublicHolidays] = useState<string[]>([]);
  const [vehicleQuotes, setVehicleQuotes] = useState<VehicleWithQuote[]>([]);

  // Step 1: Ride Details
  const [pickup, setPickup] = useState<{ address: string; placeId?: string; lat?: number; lng?: number }>({ address: '' });
  const [dropoff, setDropoff] = useState<{ address: string; placeId?: string; lat?: number; lng?: number }>({ address: '' });
  const [pickupDate, setPickupDate] = useState('');
  const [pickupTime, setPickupTime] = useState('');
  const [isReturnTrip, setIsReturnTrip] = useState(false);
  const [returnDate, setReturnDate] = useState('');
  const [returnTime, setReturnTime] = useState('');
  const [numPassengers, setNumPassengers] = useState(1);

  // Additional Requests
  const [addBabySeat, setAddBabySeat] = useState(false);
  const [addTrailer, setAddTrailer] = useState(false);
  const [meetAndGreet, setMeetAndGreet] = useState(false);

  // Step 2: Choose Ride
  const [selectedVehicleId, setSelectedVehicleId] = useState<string | null>(null);
  const [viewingVehicle, setViewingVehicle] = useState<Vehicle | null>(null);

  // Step 3: Passenger Details
  const [firstName, setFirstName] = useState('');
  const [surname, setSurname] = useState('');
  const [email, setEmail] = useState('');
  const [countryCode, setCountryCode] = useState('+27');
  const [phone, setPhone] = useState('');
  const [comments, setComments] = useState('');

  // Step 4: Payment/Confirmation
  const [bookingId, setBookingId] = useState<string | null>(null);
  const [paymentMethod, setPaymentMethod] = useState('card');

  // UI/Error State
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isMapsLoaded, setIsMapsLoaded] = useState(false);

  // Map State
  const mapRef = useRef<HTMLDivElement>(null); 
  const mapDivRef = useRef<HTMLDivElement | null>(null);
  const [mapInstance, setMapInstance] = useState<any>(null);
  const [directionsRenderer, setDirectionsRenderer] = useState<any>(null);
  const [routeStats, setRouteStats] = useState<{ distance: string; duration: string } | null>(null);
  const [numericRouteStats, setNumericRouteStats] = useState<{ distanceMeters: number; durationSeconds: number } | null>(null);

  const pickupInputRef = useRef<HTMLInputElement>(null);
  const dropoffInputRef = useRef<HTMLInputElement>(null);

  // Calculate minimum date (48 hours from now)
  const getMinDate = () => {
    const d = new Date();
    d.setDate(d.getDate() + 2);
    return d.toISOString().split('T')[0];
  };

  const minDate = getMinDate();

  // Load Initial Data if present
  useEffect(() => {
    if (initialData) {
      if (initialData.pickup) setPickup(initialData.pickup);
      if (initialData.dropoff) setDropoff(initialData.dropoff);
      if (initialData.date) setPickupDate(initialData.date);
      if (initialData.time) setPickupTime(initialData.time);
      if (initialData.passengers) setNumPassengers(initialData.passengers);
      if (initialData.vehicleId) setSelectedVehicleId(initialData.vehicleId);

      // If we have full trip details, we might want to trigger quote calculation automatically
      // But we need pricing rules loaded first, and maps loaded for route stats.
      // For now, pre-filling is a huge help.
    }
  }, [initialData]);

  // --- DATA FETCHING & INITIALIZATION ---
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [vehiclesRes, rulesRes, holidaysRes] = await Promise.all([
          supabase.from('vehicles').select('*'),
          supabase.from('pricing_rules').select('*').eq('is_active', true),
          supabase.from('public_holidays').select('holiday_date')
        ]);

        if (vehiclesRes.error) throw vehiclesRes.error;
        setVehicles(vehiclesRes.data || []);
        setPricingRules(rulesRes.data || []);
        setPublicHolidays((holidaysRes.data || []).map((h: any) => h.holiday_date));

      } catch (err: any) {
        setError('Failed to load system data. Please refresh the page.');
        console.error(err);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, []);

  // Check for Google Maps Loaded
  useEffect(() => {
    const checkGoogle = () => {
      if (window.google && window.google.maps) {
        setIsMapsLoaded(true);
      }
    };

    // Check immediately
    checkGoogle();

    // Check periodically if not yet loaded
    const intervalId = setInterval(() => {
      if (window.google && window.google.maps) {
        setIsMapsLoaded(true);
        clearInterval(intervalId);
      }
    }, 500);

    return () => clearInterval(intervalId);
  }, []);

  // Initialize Map Instance (Only Once)
  useEffect(() => {
    if (!isMapsLoaded || mapInstance) return;

    // Create a persistent container for the map
    const el = document.createElement('div');
    el.style.width = '100%';
    el.style.height = '100%';
    mapDivRef.current = el;

    const map = new window.google.maps.Map(el, {
        center: { lat: -26.2041, lng: 28.0473 }, // Joburg center
        zoom: 11,
        disableDefaultUI: true,
        styles: [
            { "featureType": "all", "elementType": "geometry.fill", "stylers": [{ "weight": "2.00" }] },
            { "featureType": "all", "elementType": "geometry.stroke", "stylers": [{ "color": "#9c9c9c" }] },
            { "featureType": "all", "elementType": "labels.text", "stylers": [{ "visibility": "on" }] },
            { "featureType": "landscape", "elementType": "all", "stylers": [{ "color": "#f2f2f2" }] },
            { "featureType": "landscape.man_made", "elementType": "geometry.fill", "stylers": [{ "color": "#ffffff" }] },
            { "featureType": "road", "elementType": "all", "stylers": [{ "saturation": -100 }, { "lightness": 45 }] },
            { "featureType": "road", "elementType": "geometry.fill", "stylers": [{ "color": "#eeeeee" }] },
            { "featureType": "water", "elementType": "all", "stylers": [{ "color": "#46bcec" }, { "visibility": "on" }] },
            { "featureType": "water", "elementType": "geometry.fill", "stylers": [{ "color": "#c8d7d4" }] }
        ]
    });

    const renderer = new window.google.maps.DirectionsRenderer({
        map,
        suppressMarkers: false,
        polylineOptions: { strokeColor: '#5b338d', strokeWeight: 5 }
    });

    setMapInstance(map);
    setDirectionsRenderer(renderer);
  }, [isMapsLoaded, mapInstance]);

  // Handle Reparenting / Moving the Map into the View
  useEffect(() => {
    if (mapInstance && mapDivRef.current && mapRef.current) {
        // Move the persistent map div into the current render slot
        if (mapRef.current !== mapDivRef.current.parentNode) {
            // Clear slot (safety)
            while (mapRef.current.firstChild) {
                mapRef.current.removeChild(mapRef.current.firstChild);
            }
            mapRef.current.appendChild(mapDivRef.current);

            // Trigger resize to ensure map renders correctly in new size
            window.google.maps.event.trigger(mapInstance, 'resize');

            // Re-center or refit bounds if route exists
            if (directionsRenderer && directionsRenderer.getDirections()) {
                 const bounds = new window.google.maps.LatLngBounds();
                 const route = directionsRenderer.getDirections().routes[0];
                 if (route) {
                     bounds.extend(route.legs[0].start_location);
                     bounds.extend(route.legs[0].end_location);
                     mapInstance.fitBounds(bounds);
                 }
            }

            // Adjust UI controls based on step
            if (currentStep > 1) {
                mapInstance.setOptions({ 
                    disableDefaultUI: true, 
                    draggable: false, 
                    zoomControl: false, 
                    scrollwheel: false, 
                    disableDoubleClickZoom: true 
                });
            } else {
                mapInstance.setOptions({ 
                    disableDefaultUI: true, 
                    draggable: true, 
                    zoomControl: true, 
                    scrollwheel: true, 
                    disableDoubleClickZoom: false 
                });
            }
        }
    }
  }, [mapInstance, currentStep, isMapsLoaded]); 

  // Autocomplete
  useEffect(() => {
    if (!isMapsLoaded) return;
    if (window.google && pickupInputRef.current && dropoffInputRef.current) {
      const autocompleteOptions = { componentRestrictions: { country: "za" }, fields: ["place_id", "formatted_address", "geometry"] };

      const pickupAutocomplete = new window.google.maps.places.Autocomplete(pickupInputRef.current, autocompleteOptions);
      pickupAutocomplete.addListener("place_changed", () => {
        const place = pickupAutocomplete.getPlace();
        if (place.place_id && place.geometry) {
            setPickup({ address: place.formatted_address || '', placeId: place.place_id, lat: place.geometry.location.lat(), lng: place.geometry.location.lng() });
        }
      });

      const dropoffAutocomplete = new window.google.maps.places.Autocomplete(dropoffInputRef.current, autocompleteOptions);
      dropoffAutocomplete.addListener("place_changed", () => {
        const place = dropoffAutocomplete.getPlace();
        if (place.place_id && place.geometry) {
            setDropoff({ address: place.formatted_address || '', placeId: place.place_id, lat: place.geometry.location.lat(), lng: place.geometry.location.lng() });
        }
      });
    }
  }, [currentStep, isMapsLoaded]); 

  // Update Route
  useEffect(() => {
    if (!isMapsLoaded) return;
    if (window.google && pickup.placeId && dropoff.placeId && directionsRenderer) {
        const directionsService = new window.google.maps.DirectionsService();
        directionsService.route({
            origin: { placeId: pickup.placeId },
            destination: { placeId: dropoff.placeId },
            travelMode: window.google.maps.TravelMode.DRIVING,
        }, (result: any, status: any) => {
            if (status === window.google.maps.DirectionsStatus.OK) {
                directionsRenderer.setDirections(result);
                const leg = result.routes[0].legs[0];
                setRouteStats({ distance: leg.distance.text, duration: leg.duration.text });
                setNumericRouteStats({ distanceMeters: leg.distance.value, durationSeconds: leg.duration.value });

                // If map is initialized, fit bounds
                if (mapInstance) {
                    const bounds = new window.google.maps.LatLngBounds();
                    bounds.extend(leg.start_location);
                    bounds.extend(leg.end_location);
                    mapInstance.fitBounds(bounds);
                }
            }
        });
    }
  }, [pickup.placeId, dropoff.placeId, directionsRenderer, mapInstance, isMapsLoaded]);

  // --- LOGIC ---
  const handleGetQuotes = async () => {
    setError(null);
    setShowEnquiry(false);

    if (!pickup.placeId || !dropoff.placeId || !pickupDate || !pickupTime) {
      setError('Please fill in all required trip details.');
      return;
    }

    setIsLoading(true);

    const pickupDateTime = new Date(`${pickupDate}T${pickupTime}`);
    const now = new Date();
    const diffHours = (pickupDateTime.getTime() - now.getTime()) / (1000 * 60 * 60);

    if (diffHours < 48) {
        setError('Bookings must be made at least 48 hours (2 days) in advance.');
        setIsLoading(false);
        return;
    }

    if (!numericRouteStats) {
        setError('Unable to calculate route.');
        setIsLoading(false);
        return;
    }

    const distanceMeters = numericRouteStats.distanceMeters;

    // RULE: Minimum distance 5km
    if (distanceMeters < 5000) {
        setError('The minimum travel distance is 5km. Please select locations further apart.');
        setIsLoading(false);
        return;
    }

    // RULE: Maximum distance 150km -> Enquiry
    if (distanceMeters > 150000) {
        setShowEnquiry(true);
        setCurrentStep(6);
        setIsLoading(false);
        return;
    }

    const isInsideJoburg = (lat?: number, lng?: number) => {
        if (!lat || !lng) return false;
        return (lat >= JOBURG_BOUNDS.south && lat <= JOBURG_BOUNDS.north && lng >= JOBURG_BOUNDS.west && lng <= JOBURG_BOUNDS.east);
    };

    if (!isInsideJoburg(pickup.lat, pickup.lng) || !isInsideJoburg(dropoff.lat, dropoff.lng)) {
        setShowEnquiry(true);
        setCurrentStep(6);
        setIsLoading(false);
        return;
    }

    const eligibleVehicles = vehicles.filter(v => v.capacity_seats >= numPassengers);
    if (eligibleVehicles.length === 0) {
        setError('No vehicles available for selected passengers.');
        setIsLoading(false);
        return;
    }

    try {
        const distanceKm = numericRouteStats.distanceMeters / 1000;
        const durationMinutes = Math.ceil(numericRouteStats.durationSeconds / 60);

        const getRuleValue = (type: string) => pricingRules.find(r => r.rule_type === type)?.value_cents || 0;
        const basePrice = getRuleValue('BASE_FEE');

        let weekendSurcharge = 0;
        if (pricingRules.find(r => r.rule_type === 'WEEKEND')?.days_of_week?.includes(pickupDateTime.getDay())) {
            weekendSurcharge = pricingRules.find(r => r.rule_type === 'WEEKEND')?.value_cents || 0;
        }

        let afterHoursSurcharge = 0;
        const timeStr = `${pickupTime}:00`;
        const afterHoursRule = pricingRules.find(r => r.rule_type === 'AFTER_HOURS');
        if (afterHoursRule && afterHoursRule.start_time && afterHoursRule.end_time) {
            const isOvernight = afterHoursRule.start_time > afterHoursRule.end_time;
            if (isOvernight ? (timeStr >= afterHoursRule.start_time || timeStr < afterHoursRule.end_time) : (timeStr >= afterHoursRule.start_time && timeStr < afterHoursRule.end_time)) {
                afterHoursSurcharge = afterHoursRule.value_cents;
            }
        }

        let holidaySurcharge = publicHolidays.includes(pickupDate) ? getRuleValue('PUBLIC_HOLIDAY') : 0;
        const babySeatCost = addBabySeat ? getRuleValue('ADDON_BABY_SEAT') : 0;
        const trailerCost = addTrailer ? getRuleValue('ADDON_TRAILER') : 0;

        const calculatedQuotes = eligibleVehicles.map(v => {
            const distanceCost = (v.price_per_km_cents * distanceKm);
            const returnCost = isReturnTrip ? distanceCost : 0;
            const totalCents = basePrice + distanceCost + returnCost + weekendSurcharge + afterHoursSurcharge + holidaySurcharge + babySeatCost + trailerCost;
            return {
                vehicle: v,
                quote: {
                    totalPrice: totalCents / 100,
                    distanceKm,
                    durationMinutes,
                    breakdown: { base: basePrice/100, distance: distanceCost/100, returnTripSurcharge: returnCost/100, babySeatSurcharge: babySeatCost/100, trailerSurcharge: trailerCost/100, weekendSurcharge: weekendSurcharge/100, afterHoursSurcharge: afterHoursSurcharge/100, holidaySurcharge: holidaySurcharge/100 }
                }
            };
        });

        setVehicleQuotes(calculatedQuotes);

        // If initialData had a vehicleId, verify it exists in our quotes, then proceed to Step 2
        // Or if we just ran this from the button, proceed to Step 2
        setCurrentStep(2);
        window.scrollTo(0, 0);
    } catch (err: any) {
      console.error(err);
      setError('Could not calculate quotes.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleConfirmBooking = async () => {
      setError(null);
      setIsLoading(true);

      const selectedBooking = vehicleQuotes.find(vq => vq.vehicle.id === selectedVehicleId);
      if (!selectedBooking) return;

      try {
          const { data, error } = await supabase.from('bookings').insert([{
            vehicle_id: selectedVehicleId,
            pickup_address: pickup.address,
            dropoff_address: dropoff.address,
            pickup_timestamp: `${pickupDate}T${pickupTime}`,
            is_return_trip: isReturnTrip,
            return_timestamp: isReturnTrip ? `${returnDate}T${returnTime}` : null,
            num_passengers: numPassengers,
            add_baby_seat: addBabySeat,
            add_trailer: addTrailer,
            total_price_cents: Math.round(selectedBooking.quote.totalPrice * 100),
            price_breakdown: selectedBooking.quote.breakdown,
            customer_first_name: firstName,
            customer_surname: surname,
            customer_email: email,
            customer_phone: `${countryCode} ${phone}`,
            status: 'confirmed'
          }]).select('id').single();

          if (error) throw error;
          if (data) {
              setBookingId(data.id);
              setCurrentStep(5);
          }
      } catch (err: any) {
          setError(err.message || 'Booking failed.');
      } finally {
          setIsLoading(false);
      }
  };

  const nextStep = () => {
      if (currentStep === 2 && !selectedVehicleId) return;
      if (currentStep === 3) {
          if (!firstName || !surname || !email || !phone) {
              setError('Please fill in all details');
              return;
          }
      }
      setError(null);
      setCurrentStep(prev => prev + 1);
      window.scrollTo(0, 0);
  };

  const prevStep = () => {
      setError(null);
      if (currentStep === 6) {
          // If we are on the Enquiry screen (Step 6), go back to Ride Details (Step 1)
          // instead of Step 5 (Booking Confirmed).
          setShowEnquiry(false);
          setCurrentStep(1);
      } else {
          setCurrentStep(prev => prev - 1);
      }
  };

  const startNewBooking = () => {
    setCurrentStep(1);
    setShowEnquiry(false);
    setBookingId(null);
    setPickup({ address: '' });
    setDropoff({ address: '' });
    setPickupDate('');
    setPickupTime('');
    setSelectedVehicleId(null);
    setRouteStats(null);
    setNumericRouteStats(null);
  };

  // --- RENDER HELPERS ---
  const renderProgressBar = () => (
    <div className="flex justify-center items-center w-full mb-12">
        <div className="flex items-center w-full max-w-4xl px-4">
            {[
                { step: 1, label: 'Ride Details' },
                { step: 2, label: 'Vehicle' },
                { step: 3, label: 'Details' },
                { step: 4, label: 'Payment' }
            ].map((item, index) => {
                const isCompleted = currentStep > item.step;
                const isActive = currentStep === item.step;

                return (
                    <React.Fragment key={item.step}>
                        <div 
                            onClick={() => {
                                if (isCompleted) {
                                    setCurrentStep(item.step);
                                    window.scrollTo(0, 0);
                                }
                            }}
                            className={`flex flex-col items-center relative z-10 transition-transform ${isCompleted ? 'cursor-pointer hover:scale-105' : ''}`}
                        >
                            <div className={`size-10 rounded-full flex items-center justify-center font-bold transition-colors duration-300 ${
                                isActive ? 'bg-accent-gold text-white shadow-lg ring-4 ring-accent-gold/20' : 
                                isCompleted ? 'bg-accent-gold text-white' : 
                                'bg-gray-200 text-gray-400'
                            }`}>
                            {isCompleted ? <span className="material-symbols-outlined !text-xl">check</span> : item.step}
                            </div>
                            <span className={`absolute top-12 text-[10px] font-bold whitespace-nowrap uppercase tracking-widest ${
                                currentStep >= item.step ? 'text-charcoal' : 'text-gray-300'
                            }`}>{item.label}</span>
                        </div>
                        {index < 3 && (
                            <div className={`flex-1 h-[2px] mx-4 transition-colors duration-300 ${
                                currentStep > item.step ? 'bg-accent-gold' : 'bg-gray-200'
                            }`}></div>
                        )}
                    </React.Fragment>
                );
            })}
        </div>
    </div>
  );

  const renderRideDetails = () => (
    <div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100">
        <h1 className="text-2xl font-display font-bold text-charcoal mb-6">Enter Ride Details</h1>
        <div className="space-y-6">
            <div className="bg-gray-50/50 p-6 rounded-2xl border border-gray-100 relative">
                <div className="flex gap-4">
                    <div className="flex flex-col items-center pt-3 relative">
                        <div className="size-6 rounded-full border border-accent-gold/30 bg-white flex items-center justify-center z-10 shadow-sm">
                            <span className="material-symbols-outlined !text-sm text-accent-gold">arrow_upward</span>
                        </div>
                        <div className="w-[1px] bg-gray-300 border-l border-dashed h-full absolute top-6 bottom-6 -z-0"></div>
                        <div className="mt-auto size-6 rounded-full border border-emerald-500/30 bg-white flex items-center justify-center z-10 shadow-sm">
                            <span className="material-symbols-outlined !text-sm text-emerald-600">arrow_downward</span>
                        </div>
                    </div>
                    <div className="flex-1 space-y-6">
                        <div>
                            <label className="block text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1.5">Pick-up Location</label>
                            <input 
                                ref={pickupInputRef} 
                                type="text" 
                                defaultValue={pickup.address}
                                onChange={(e) => setPickup(prev => ({ ...prev, address: e.target.value, placeId: undefined }))}
                                placeholder={isMapsLoaded ? "Start typing address..." : "Loading maps..."} 
                                disabled={!isMapsLoaded} 
                                className="w-full bg-white border-none rounded-xl h-12 text-sm focus:ring-1 focus:ring-accent-gold shadow-sm placeholder:text-gray-300 font-medium" 
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1.5">Drop-off Location</label>
                            <input 
                                ref={dropoffInputRef} 
                                type="text" 
                                defaultValue={dropoff.address}
                                onChange={(e) => setDropoff(prev => ({ ...prev, address: e.target.value, placeId: undefined }))}
                                placeholder={isMapsLoaded ? "Start typing address..." : "Loading maps..."} 
                                disabled={!isMapsLoaded} 
                                className="w-full bg-white border-none rounded-xl h-12 text-sm focus:ring-1 focus:ring-accent-gold shadow-sm placeholder:text-gray-300 font-medium" 
                            />
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div className="relative group">
                    <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-accent-gold transition-colors">calendar_today</span>
                    <input type="date" min={minDate} value={pickupDate} onChange={e => setPickupDate(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl h-14 pl-12 text-sm focus:ring-1 focus:ring-accent-gold font-medium text-charcoal"/>
                </div>
                <div className="relative group">
                    <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-accent-gold transition-colors">schedule</span>
                    <input type="time" value={pickupTime} onChange={e => setPickupTime(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl h-14 pl-12 text-sm focus:ring-1 focus:ring-accent-gold font-medium text-charcoal"/>
