  distanceKm: number;
  durationMinutes: number;
  breakdown: {
    base: number;
    distance: number;
    returnTripSurcharge: number;
    babySeatSurcharge: number;
    trailerSurcharge: number;
    weekendSurcharge: number;
    afterHoursSurcharge: number;
    holidaySurcharge: number;
