  // Handle Reparenting / Moving the Map into the View
  useEffect(() => {
    if (mapInstance && mapDivRef.current && mapRef.current) {
        // Move the persistent map div into the current render slot
        if (mapRef.current !== mapDivRef.current.parentNode) {
            // Clear slot (safety)
            while (mapRef.current.firstChild) {
                mapRef.current.removeChild(mapRef.current.firstChild);
            }
            mapRef.current.appendChild(mapDivRef.current);

            // Trigger resize to ensure map renders correctly in new size
            window.google.maps.event.trigger(mapInstance, 'resize');

            // Re-center or refit bounds if route exists
            if (directionsRenderer && directionsRenderer.getDirections()) {
                 const bounds = new window.google.maps.LatLngBounds();
                 const route = directionsRenderer.getDirections().routes[0];
                 if (route) {
                     bounds.extend(route.legs[0].start_location);
                     bounds.extend(route.legs[0].end_location);
                     mapInstance.fitBounds(bounds);
                 }
            }

            // Adjust UI controls based on step
            if (currentStep > 1) {
                mapInstance.setOptions({ 
                    disableDefaultUI: true, 
                    draggable: false, 
                    zoomControl: false, 
                    scrollwheel: false, 
                    disableDoubleClickZoom: true 
                });
            } else {
                mapInstance.setOptions({ 
                    disableDefaultUI: true, 
                    draggable: true, 
                    zoomControl: true, 
                    scrollwheel: true, 
                    disableDoubleClickZoom: false 
