  // Autocomplete
  useEffect(() => {
    if (!isMapsLoaded || !pickupInputRef.current || !dropoffInputRef.current) return;

    const initAutocomplete = async () => {
      try {
        const { Autocomplete } = await window.google.maps.importLibrary("places");
        const { Place } = await window.google.maps.importLibrary("places");

        const options = { 
          componentRestrictions: { country: "za" }, 
          fields: ["place_id", "name"] // Request minimal data initially
        };

        // Pickup Autocomplete
        const pickupAutocomplete = new Autocomplete(pickupInputRef.current, options);
        pickupAutocomplete.addListener("place_changed", async () => {
          const placeResult = pickupAutocomplete.getPlace();
          if (placeResult?.place_id) {
            const place = new Place({ id: placeResult.place_id });
            await place.fetchFields({ fields: ['location', 'formattedAddress'] });
            if (place.location && place.formattedAddress) {
              setPickup({
                address: place.formattedAddress,
                placeId: placeResult.place_id,
                lat: place.location.lat(),
                lng: place.location.lng()
              });
            }
          }
        });

        // Dropoff Autocomplete
        const dropoffAutocomplete = new Autocomplete(dropoffInputRef.current, options);
        dropoffAutocomplete.addListener("place_changed", async () => {
          const placeResult = dropoffAutocomplete.getPlace();
          if (placeResult?.place_id) {
            const place = new Place({ id: placeResult.place_id });
            await place.fetchFields({ fields: ['location', 'formattedAddress'] });
            if (place.location && place.formattedAddress) {
              setDropoff({
                address: place.formattedAddress,
                placeId: placeResult.place_id,
                lat: place.location.lat(),
                lng: place.location.lng()
              });
            }
          }
        });
      } catch (error) {
        console.error("Error loading Google Maps Places library", error);
      }
    };

    initAutocomplete();

