                            className={`flex flex-col items-center relative z-10 transition-transform ${isCompleted ? 'cursor-pointer hover:scale-105' : ''}`}
                        >
                            <div className={`size-10 rounded-full flex items-center justify-center font-bold transition-colors duration-300 ${
                                isActive ? 'bg-accent-gold text-white shadow-lg ring-4 ring-accent-gold/20' : 
