                  onClick={e => e.stopPropagation()}
              >
                  <button 
                      onClick={() => setViewingVehicle(null)}
                      className="absolute top-4 right-4 z-10 size-10 bg-white/90 backdrop-blur rounded-full flex items-center justify-center hover:bg-gray-100 transition-colors shadow-sm"
                  >
                      <span className="material-symbols-outlined text-charcoal">close</span>
                  </button>

                  <div className="h-64 w-full relative bg-gray-100">
                      <img src={viewingVehicle.hero_image_url} alt={viewingVehicle.name} className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
                      <div className="absolute bottom-6 left-6 text-white">
                          <h2 className="text-3xl font-display font-bold">{viewingVehicle.name.split('|')[0]}</h2>
                          <p className="opacity-90 text-sm">{viewingVehicle.name.split('|')[1] || 'Luxury Vehicle'}</p>
