    return (<div className="bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden sticky top-24"><div className="p-4 bg-white border-b border-gray-100 z-20 relative flex justify-between items-center"><h3 className="font-bold text-lg text-charcoal">Booking Summary</h3></div><div className="relative h-48 w-full bg-gray-100"><div ref={mapRef} className="w-full h-full absolute inset-0 z-0" />{routeStats && (<div className="absolute bottom-3 right-3 bg-white/90 backdrop-blur px-3 py-1.5 rounded-lg shadow-sm border border-gray-200 text-xs font-bold text-charcoal z-10 flex items-center gap-2 animate-in fade-in"><span>{routeStats.distance}</span><span className="text-gray-300">•</span><span>{routeStats.duration}</span></div>)}</div><div className="p-6 space-y-6">{selectedQuote ? (<div className="flex items-center gap-4"><div className="size-14 bg-white rounded-xl p-1 border border-gray-100 flex items-center justify-center shadow-sm"><img src={selectedQuote.vehicle.hero_image_url} alt="Vehicle" className="w-full h-full object-contain" /></div><div className="flex-1"><h4 className="font-bold text-sm text-charcoal">{selectedQuote.vehicle.name.split('|')[0]}</h4><p className="text-[10px] text-charcoal/50">{selectedQuote.vehicle.name.split('|')[1] || 'Luxury Class'} • {numPassengers} Passengers</p></div><div className="text-right"><span className="font-black text-lg text-accent-gold">R{selectedQuote.quote.totalPrice.toFixed(0)}</span></div></div>) : (<div className="flex items-center gap-4 opacity-50"><div className="size-14 bg-gray-100 rounded-xl flex items-center justify-center"><span className="material-symbols-outlined text-charcoal/30">directions_car</span></div><div><h4 className="font-bold text-sm text-charcoal">No Vehicle Selected</h4><p className="text-[10px] text-charcoal/50">Please select a vehicle</p></div></div>)}<hr className="border-gray-100" /><div className="relative pl-4"><div className="absolute top-2 left-0 bottom-4 w-0.5 bg-gray-200 border-l border-dashed border-gray-300"></div><div className="mb-6 relative"><div className="absolute -left-[5px] top-1.5 size-2.5 rounded-full bg-accent-gold ring-2 ring-white"></div><p className="text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1">Pick-up</p><p className="text-sm font-bold text-charcoal leading-tight mb-1">{pickup.address}</p><p className="text-xs text-charcoal/50">{pickupDate} • {pickupTime}</p></div><div className="relative"><div className="absolute -left-[5px] top-1.5 size-2.5 rounded-full bg-charcoal ring-2 ring-white"></div><p className="text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1">Drop-off</p><p className="text-sm font-bold text-charcoal leading-tight">{dropoff.address}</p></div></div>{(addBabySeat || meetAndGreet) && (<div className="pt-2"><p className="text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-2">ADD-ONS</p><div className="flex flex-wrap gap-2">{addBabySeat && <span className="px-3 py-1 bg-gray-100 rounded-full text-[10px] font-bold text-charcoal/70">Baby Seat</span>}{meetAndGreet && <span className="px-3 py-1 bg-gray-100 rounded-full text-[10px] font-bold text-charcoal/70">Meet & Greet</span>}</div></div>)}<div className="space-y-3 pt-2"><button onClick={btnAction} disabled={btnDisabled} className="w-full h-12 bg-charcoal text-white rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-black transition-all shadow-lg text-xs tracking-widest uppercase disabled:opacity-50 disabled:cursor-not-allowed group">{btnText}{!isLoading && <span className="material-symbols-outlined group-hover:translate-x-1 transition-transform !text-base">arrow_forward</span>}</button>{currentStep > 1 && (<button onClick={prevStep} className="w-full h-12 bg-white border border-gray-200 text-charcoal rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-gray-50 transition-all text-xs tracking-widest uppercase">Back</button>)}</div></div></div>);
  };

