            </div>
            <button onClick={handleSearchClick} disabled={loading || !mapsLoaded} className="w-full h-16 rounded-xl bg-charcoal text-white flex items-center justify-center gap-3 hover:bg-black transition-all group font-black tracking-widest uppercase text-xs shadow-xl disabled:opacity-50 disabled:cursor-not-allowed">
                {loading ? 'Calculating...' : 'Search Vehicles'}
