// Custom hook for debouncing
const useDebounce = <T,>(value: T, delay: number): T => {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);
    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);
  return debouncedValue;
};


// --- TYPE DEFINITIONS ---
interface Vehicle {
  id: string;
  name: string;
  price_per_km_cents: number;
  capacity_seats: number;
  capacity_bags: number;
  hero_image_url: string;
  specs?: any; 
  details?: {
    features: string[];
    idealFor: string[];
  };
}

interface Quote {
  totalPrice: number;
  distanceKm: number;
  durationMinutes: number;
  breakdown: {
    base: number;
    distance: number;
    returnTripSurcharge: number;
    babySeatSurcharge: number;
    trailerSurcharge: number;
    weekendSurcharge: number;
    afterHoursSurcharge: number;
    holidaySurcharge: number;
  };
}

interface VehicleWithQuote {
    vehicle: Vehicle;
    quote: Quote;
}

interface PricingRule {
  rule_type: string;
  value_cents: number;
  days_of_week?: number[];
  start_time?: string;
  end_time?: string;
}

interface BookingDashboardProps {
  initialData?: {
    pickup?: { address: string; placeId: string; lat: number; lng: number };
    dropoff?: { address: string; placeId: string; lat: number; lng: number };
    date?: string;
    time?: string;
    passengers?: number;
    vehicleId?: string;
  } | null;
}

const JOBURG_BOUNDS = { south: -26.35, west: 27.85, north: -26.05, east: 28.25 };

// --- MAIN COMPONENT ---
const BookingDashboard: React.FC<BookingDashboardProps> = ({ initialData }) => {
  const [currentStep, setCurrentStep] = useState(1);
  const [showEnquiry, setShowEnquiry] = useState(false);
  const [vehicles, setVehicles] = useState<Vehicle[]>([]);
  const [pricingRules, setPricingRules] = useState<PricingRule[]>([]);
  const [publicHolidays, setPublicHolidays] = useState<string[]>([]);
  const [vehicleQuotes, setVehicleQuotes] = useState<VehicleWithQuote[]>([]);
