                 {currentStep === 5 && renderSuccess()}
                 {currentStep === 6 && renderEnquiry()}
                 {error && (<div className="bg-red-50 border border-red-100 p-4 rounded-xl mt-4 flex gap-3 items-start animate-in fade-in slide-in-from-top-2"><span className="material-symbols-outlined text-red-500 !text-lg mt-0.5">error</span><p className="text-red-600 text-xs leading-relaxed">{error}</p></div>)}
             </div>
             {currentStep !== 5 && currentStep !== 6 && (
                 <div className={`${currentStep === 1 ? 'lg:col-span-2' : 'lg:col-span-1'}`}>
                     {currentStep === 1 ? (
                         <div className="h-[600px] bg-gray-200 rounded-2xl overflow-hidden relative shadow-lg border border-gray-200">
                             <div ref={mapRef} className="w-full h-full absolute inset-0 z-0"></div>
                             {isMapsLoaded && routeStats && (<div className="absolute top-6 right-6 bg-white/90 backdrop-blur-md px-6 py-4 rounded-xl shadow-lg border border-gray-200 z-10 animate-in slide-in-from-top-4 fade-in"><p className="text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1">Estimated Travel Time</p><span className="text-2xl font-black text-charcoal">{routeStats.duration}</span><p className="text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mt-2 mb-1">Distance</p><span className="text-lg font-bold text-charcoal">{routeStats.distance}</span></div>)}
                         </div>
                     ) : ( renderTripSummary() )}
                 </div>
             )}
          </div>
       </div>
       {renderVehicleDetailsPopup()}
    </div>
  );
};

export default BookingDashboard;

