import React, { useState } from 'react';
import { supabase } from '../lib/supabaseClient';
import Logo from './Logo';

interface AuthPageProps {
  initialMode: 'login' | 'signup';
  onAuthSuccess: () => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ initialMode, onAuthSuccess }) => {
  const [mode, setMode] = useState(initialMode);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);

  const handleAuthAction = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setMessage(null);

    if (mode === 'signup') {
      if (password !== confirmPassword) {
        setError("Passwords do not match.");
        setLoading(false);
        return;
      }
      if (password.length < 6) {
        setError("Password must be at least 6 characters long.");
        setLoading(false);
        return;
      }
      const { error } = await supabase.auth.signUp({ email, password });
      if (error) {
        setError(error.message);
      } else {
        setMessage("Success! Please check your email for a verification link.");
      }
    } else { // login
      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) {
        setError(error.message);
      } else {
        onAuthSuccess();
      }
    }
    setLoading(false);
  };

  const isSignup = mode === 'signup';
  const title = isSignup ? 'Create Your Account' : 'Welcome Back';
  const subtitle = isSignup ? 'Join us to manage your journeys.' : 'Log in to access your account.';
  const buttonText = isSignup ? 'Sign Up' : 'Login';
  const toggleText = isSignup ? 'Already have an account?' : "Don't have an account?";
  const toggleLinkText = isSignup ? 'Log In' : 'Sign Up';

  return (
    <div className="min-h-screen flex items-center justify-center bg-background-light pt-40 pb-12 px-4">
      <div className="w-full max-w-md">
        <div className="bg-white p-8 rounded-2xl shadow-2xl border border-charcoal/5">
          <div className="text-center mb-8">
            <h1 className="text-3xl font-display font-bold text-charcoal">{title}</h1>
            <p className="text-charcoal/50 mt-2">{subtitle}</p>
          </div>

          {message ? (
            <div className="bg-green-50 text-green-700 p-4 rounded-lg text-center text-sm">
              {message}
            </div>
          ) : (
            <form onSubmit={handleAuthAction} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-charcoal/40 uppercase tracking-widest mb-2 ml-1" htmlFor="email">Email</label>
                <input
                  id="email"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full bg-background-light border-none rounded-xl h-14 px-4 text-sm focus:ring-1 focus:ring-primary placeholder:text-charcoal/30 font-medium"
                  placeholder="name@example.com"
                  required
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-charcoal/40 uppercase tracking-widest mb-2 ml-1" htmlFor="password">Password</label>
                <input
                  id="password"
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-background-light border-none rounded-xl h-14 px-4 text-sm focus:ring-1 focus:ring-primary placeholder:text-charcoal/30 font-medium"
                  placeholder="••••••••"
                  required
                />
              </div>
              {isSignup && (
                <div>
                  <label className="block text-[10px] font-black text-charcoal/40 uppercase tracking-widest mb-2 ml-1" htmlFor="confirm-password">Confirm Password</label>
                  <input
                    id="confirm-password"
                    type="password"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    className="w-full bg-background-light border-none rounded-xl h-14 px-4 text-sm focus:ring-1 focus:ring-primary placeholder:text-charcoal/30 font-medium"
                    placeholder="••••••••"
                    required
                  />
                </div>
              )}
              {error && (
                <p className="text-red-500 text-xs text-center">{error}</p>
              )}
              <button
                type="submit"
                disabled={loading}
                className="w-full h-14 bg-primary text-white rounded-xl font-bold flex items-center justify-center hover:bg-charcoal transition-all shadow-lg shadow-primary/20 text-sm tracking-widest uppercase disabled:opacity-50"
              >
                {loading ? 'Processing...' : buttonText}
              </button>
            </form>
          )}

          <div className="text-center mt-6">
            <p className="text-sm text-charcoal/50">
              {toggleText}{' '}
              <button onClick={() => setMode(isSignup ? 'login' : 'signup')} className="font-bold text-primary hover:underline">
                {toggleLinkText}
              </button>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

