import React, { useState } from 'react';
import { supabase } from '../lib/supabaseClient';

interface AuthPageProps {
  initialMode: 'login' | 'signup';
  onAuthSuccess: () => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ initialMode, onAuthSuccess }) => {
  const [mode, setMode] = useState(initialMode);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);

  const handleAuthAction = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setMessage(null);

    if (mode === 'signup') {
      if (password !== confirmPassword) {
        setError("Passwords do not match.");
        setLoading(false);
        return;
      }
      if (password.length < 6) {
        setError("Password must be at least 6 characters long.");
        setLoading(false);
        return;
      }
      const { error } = await supabase.auth.signUp({ email, password });
      if (error) {
        setError(error.message);
      } else {
        setMessage("Success! Please check your email for a verification link.");
      }
    } else { // login
      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) {
        setError(error.message);
      } else {
        onAuthSuccess();
      }
    }
    setLoading(false);
  };

  const handleGoogleSignIn = async () => {
    setLoading(true);
    setError(null);
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: window.location.origin,
      },
    });
    if (error) {
      setError(error.message);
      setLoading(false);
    }
    // On success, Supabase handles the redirect.
  };

  const isSignup = mode === 'signup';
  const title = isSignup ? 'Create Your Account' : 'Welcome Back';
  const subtitle = isSignup ? 'Join us to manage your journeys.' : 'Log in to access your account.';
  const buttonText = isSignup ? 'Sign Up' : 'Login';
  const toggleText = isSignup ? 'Already have an account?' : "Don't have an account?";
  const toggleLinkText = isSignup ? 'Log In' : 'Sign Up';

  return (
    <div className="min-h-screen flex items-center justify-center bg-background-light pt-40 pb-12 px-4">
      <div className="w-full max-w-md">
        <div className="bg-white p-8 rounded-2xl shadow-2xl border border-charcoal/5">
          <div className="text-center mb-8">
            <h1 className="text-3xl font-display font-bold text-charcoal">{title}</h1>
            <p className="text-charcoal/50 mt-2">{subtitle}</p>
          </div>

          {message ? (
            <div className="bg-green-50 text-green-700 p-4 rounded-lg text-center text-sm">
              {message}
            </div>
          ) : (
            <>
              <form onSubmit={handleAuthAction} className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black text-charcoal/40 uppercase tracking-widest mb-2 ml-1" htmlFor="email">Email</label>
                  <input
                    id="email"
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full bg-background-light border-none rounded-xl h-14 px-4 text-sm focus:ring-1 focus:ring-primary placeholder:text-charcoal/30 font-medium"
                    placeholder="name@example.com"
                    required
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-charcoal/40 uppercase tracking-widest mb-2 ml-1" htmlFor="password">Password</label>
                  <input
                    id="password"
                    type="password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full bg-background-light border-none rounded-xl h-14 px-4 text-sm focus:ring-1 focus:ring-primary placeholder:text-charcoal/30 font-medium"
                    placeholder="••••••••"
                    required
                  />
                </div>
                {isSignup && (
                  <div>
                    <label className="block text-[10px] font-black text-charcoal/40 uppercase tracking-widest mb-2 ml-1" htmlFor="confirm-password">Confirm Password</label>
                    <input
                      id="confirm-password"
                      type="password"
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      className="w-full bg-background-light border-none rounded-xl h-14 px-4 text-sm focus:ring-1 focus:ring-primary placeholder:text-charcoal/30 font-medium"
                      placeholder="••••••••"
                      required
                    />
                  </div>
                )}
                {error && (
                  <p className="text-red-500 text-xs text-center">{error}</p>
                )}
                <button
                  type="submit"
                  disabled={loading}
                  className="w-full h-14 bg-primary text-white rounded-xl font-bold flex items-center justify-center hover:bg-charcoal transition-all shadow-lg shadow-primary/20 text-sm tracking-widest uppercase disabled:opacity-50"
                >
                  {loading ? 'Processing...' : buttonText}
                </button>
              </form>

              <div className="flex items-center my-6">
                <div className="flex-grow border-t border-charcoal/10"></div>
                <span className="flex-shrink mx-4 text-xs font-bold text-charcoal/40 uppercase">Or</span>
                <div className="flex-grow border-t border-charcoal/10"></div>
              </div>

              <button
                type="button"
                onClick={handleGoogleSignIn}
                disabled={loading}
                className="w-full h-14 bg-white border border-charcoal/10 text-charcoal rounded-xl font-bold flex items-center justify-center gap-3 hover:bg-background-light transition-all shadow-sm text-sm disabled:opacity-50"
              >
                <svg className="size-5" role="img" aria-label="Google logo" viewBox="0 0 48 48">
                  <path fill="#FFC107" d="M43.611,20.083H42V20H24v8h11.303c-1.649,4.657-6.08,8-11.303,8c-6.627,0-12-5.373-12-12 c0-6.627,5.373-12,12-12c3.059,0,5.842,1.154,7.961,3.039l5.657-5.657C34.046,6.053,29.268,4,24,4C12.955,4,4,12.955,4,24 c0,11.045,8.955,20,20,20c11.045,0,20-8.955,20-20C44,22.659,43.862,21.35,43.611,20.083z"></path>
                  <path fill="#FF3D00" d="M6.306,14.691l6.571,4.819C14.655,15.108,18.961,12,24,12c3.059,0,5.842,1.154,7.961,3.039l5.657-5.657 C34.046,6.053,29.268,4,24,4C16.318,4,9.656,8.337,6.306,14.691z"></path>
                  <path fill="#4CAF50" d="M24,44c5.166,0,9.86-1.977,13.409-5.192l-6.19-5.238C29.211,35.091,26.715,36,24,36 c-5.202,0-9.619-3.317-11.283-7.946l-6.522,5.025C9.505,39.556,16.227,44,24,44z"></path>
                  <path fill="#1976D2" d="M43.611,20.083H42V20H24v8h11.303c-0.792,2.237-2.231,4.166-4.087,5.571 c0.001-0.001,0.002-0.001,0.003-0.002l6.19,5.238C36.971,39.205,44,34,44,24C44,22.659,43.862,21.35,43.611,20.083z"></path>
                </svg>
                Continue with Google
              </button>
            </>
          )}

          <div className="text-center mt-6">
            <p className="text-sm text-charcoal/50">
              {toggleText}{' '}
              <button onClick={() => setMode(isSignup ? 'login' : 'signup')} className="font-bold text-primary hover:underline">
                {toggleLinkText}
              </button>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;

import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabaseClient';
import { Session } from '@supabase/supabase-js';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import BookingBar, { SearchParams } from './components/BookingBar';
import HomeSearchResults from './components/HomeSearchResults';
import Experience from './components/Experience';
import ServicesList from './components/ServicesList';
import Fleet from './components/Fleet';
import AboutUs from './components/AboutUs';
import Mission from './components/Mission';
import WhyChooseUs from './components/WhyChooseUs';
import WhoFor from './components/WhoFor';
import FAQ from './components/FAQ';
import ContactCTA from './components/ContactCTA';
import Footer from './components/Footer';
import BookingDashboard from './components/BookingDashboard';
import FleetPage from './components/FleetPage';
import AboutPage from './components/AboutPage';
import ServicesPage from './components/ServicesPage';
import ContactPage from './components/ContactPage';
import RevealSection from './components/RevealSection';
import AuthPage from './components/AuthPage';
import FloatingContactButton from './components/FloatingContactButton';

interface VehicleResult {
  vehicle: any;
  totalPrice: number;
}

const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [currentView, setCurrentView] = useState<'home' | 'booking' | 'fleet' | 'about' | 'services' | 'contact' | 'account' | 'auth'>('home');
  const [targetSection, setTargetSection] = useState<string | null>(null);
  const [initialBookingData, setInitialBookingData] = useState<any>(null);
  const [initialServiceId, setInitialServiceId] = useState<string | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');

  // Data State for Home Search
  const [vehicles, setVehicles] = useState<any[]>([]);
  const [pricingRules, setPricingRules] = useState<any[]>([]);
  const [publicHolidays, setPublicHolidays] = useState<string[]>([]);
  const [homeSearchResults, setHomeSearchResults] = useState<VehicleResult[]>([]);
  const [currentSearchParams, setCurrentSearchParams] = useState<SearchParams | null>(null);

  // Auth Listener
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        setSession(session);
        if (_event === 'SIGNED_IN') {
            setCurrentView('account');
        }
        if (_event === 'SIGNED_OUT') {
            setCurrentView('home');
        }
    });

    return () => subscription.unsubscribe();
  }, []);

  // Fetch Data on Load
  useEffect(() => {
    const fetchSystemData = async () => {
      try {
        const [v, r, h] = await Promise.all([
          supabase.from('vehicles').select('*'),
          supabase.from('pricing_rules').select('*').eq('is_active', true),
          supabase.from('public_holidays').select('holiday_date')
        ]);
        setVehicles(v.data || []);
        setPricingRules(r.data || []);
        setPublicHolidays((h.data || []).map((x: any) => x.holiday_date));
      } catch (err) {
        console.error("Error fetching initial data", err);
      }
    };
    fetchSystemData();
  }, []);

  const handleGoToBooking = () => {
    setInitialBookingData(null); 
    setCurrentView('booking');
    window.scrollTo(0, 0);
  };

  const handleBookVehicle = (vehicleId: string) => {
    // If we have search params from home search, pass them along
    if (currentSearchParams) {
      setInitialBookingData({
        pickup: currentSearchParams.pickup,
        dropoff: currentSearchParams.dropoff,
        date: currentSearchParams.date,
        time: currentSearchParams.time,
        passengers: currentSearchParams.passengers,
        vehicleId: vehicleId
      });
    } else {
      setInitialBookingData({ vehicleId });
    }
    setCurrentView('booking');
    window.scrollTo(0, 0);
  };

  const handleGoToHome = () => {
    setCurrentView('home');
    window.scrollTo(0, 0);
  };

  const handleGoToFleet = () => {
    setCurrentView('fleet');
    window.scrollTo(0, 0);
  };

  const handleGoToAbout = () => {
    setCurrentView('about');
    window.scrollTo(0, 0);
  };

  const handleGoToServices = () => {
    setInitialServiceId(null); 
    setCurrentView('services');
    window.scrollTo(0, 0);
  };

  const handleGoToContact = () => {
    setCurrentView('contact');
    window.scrollTo(0, 0);
  };

  const handleGoToAccount = () => {
    if (session) {
      setCurrentView('account');
      window.scrollTo(0, 0);
    } else {
      handleLogin();
    }
  };

  const handleLogin = () => {
    setAuthMode('login');
    setCurrentView('auth');
    window.scrollTo(0,0);
  };

  const handleSignUp = () => {
    setAuthMode('signup');
    setCurrentView('auth');
    window.scrollTo(0,0);
  };

  const handleLogout = async () => {
    const { error } = await supabase.auth.signOut();
    if (error) {
        console.error("Error signing out:", error);
    }
  };

  const handleSelectService = (serviceId: string) => {
    setInitialServiceId(serviceId);
    setCurrentView('services');
    window.scrollTo(0, 0);
  };

  const handleGoToSection = (sectionId: string) => {
    if (currentView !== 'home') {
      setTargetSection(sectionId);
      setCurrentView('home');
    } else {
      setTimeout(() => {
        const element = document.getElementById(sectionId);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        }
      }, 100);
    }
  };

  // Perform Search Logic (Client Side Calculation)
  const handleHomeSearch = (params: SearchParams) => {
    setCurrentSearchParams(params);

    // Filter eligible vehicles
    const eligibleVehicles = vehicles.filter(v => v.capacity_seats >= params.passengers);

    if (eligibleVehicles.length === 0) {
      alert("No vehicles available for this number of passengers.");
      return;
    }

    const pickupDate = new Date(`${params.date}T${params.time}`);
    const getRuleValue = (type: string) => pricingRules.find(r => r.rule_type === type)?.value_cents || 0;

    // Calculate Surcharges
    const basePrice = getRuleValue('BASE_FEE');

    let weekendSurcharge = 0;
    const weekendRule = pricingRules.find(r => r.rule_type === 'WEEKEND');
    if (weekendRule && weekendRule.days_of_week && weekendRule.days_of_week.includes(pickupDate.getDay())) {
        weekendSurcharge = weekendRule.value_cents;
    }

    let afterHoursSurcharge = 0;
    const timeStr = `${params.time}:00`;
    const afterHoursRule = pricingRules.find(r => r.rule_type === 'AFTER_HOURS');
    if (afterHoursRule && afterHoursRule.start_time && afterHoursRule.end_time) {
        const isOvernight = afterHoursRule.start_time > afterHoursRule.end_time;
        if (isOvernight ? (timeStr >= afterHoursRule.start_time || timeStr < afterHoursRule.end_time) : (timeStr >= afterHoursRule.start_time && timeStr < afterHoursRule.end_time)) {
            afterHoursSurcharge = afterHoursRule.value_cents;
        }
    }

    let holidaySurcharge = publicHolidays.includes(params.date) ? getRuleValue('PUBLIC_HOLIDAY') : 0;

    // Calculate per vehicle
    const results = eligibleVehicles.map(v => {
      const distanceCost = (v.price_per_km_cents * params.distanceKm);
      const totalCents = basePrice + distanceCost + weekendSurcharge + afterHoursSurcharge + holidaySurcharge;

      return {
        vehicle: v,
        totalPrice: totalCents / 100
      };
    });

    setHomeSearchResults(results);

    // Scroll to results
    setTimeout(() => {
      const el = document.getElementById('search-results');
      if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 200);
  };

  // Effect to handle scrolling after view changes to 'home'
  useEffect(() => {
    if (currentView === 'home' && targetSection) {
      setTimeout(() => {
        const element = document.getElementById(targetSection);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        }
        setTargetSection(null);
      }, 100);
    }
  }, [currentView, targetSection]);

  return (
    <div className="relative min-h-screen bg-background-light">
      <Navbar 
        session={session}
        currentView={currentView}
        onBookNow={handleGoToBooking} 
        onGoToFleet={handleGoToFleet}
        onGoToHome={handleGoToHome}
        onGoToAbout={handleGoToAbout}
        onGoToServices={handleGoToServices}
        onGoToContact={handleGoToContact}
        onLogin={handleLogin}
        onSignUp={handleSignUp}
        onLogout={handleLogout}
        onGoToAccount={handleGoToAccount}
        onGoToSection={handleGoToSection}
      />

      <main className="pt-0">
        {currentView === 'home' && (
          <div className="fade-in">
            <Hero onExplore={handleGoToFleet} onSeeStory={handleGoToAbout} />

            {/* Search Bar - Reveals with slight delay */}
            <div className="relative z-30 px-6 max-w-[1100px] mx-auto -mt-16">
              <RevealSection delay={200} variant="fade-up">
                <BookingBar onSearch={handleHomeSearch} />
              </RevealSection>
            </div>

            {/* Search Results Section */}
            <div className="mt-12">
               {homeSearchResults.length > 0 && (
                   <RevealSection variant="fade-up">
                       <HomeSearchResults results={homeSearchResults} onBook={handleBookVehicle} />
                   </RevealSection>
               )}
            </div>

            {/* "Meticulously Crafted Service" Section */}
            <RevealSection variant="fade-up">
              <Experience />
            </RevealSection>

            {/* Services - Staggered Slide In effect could be simulated by container animation */}
            <RevealSection variant="fade-up">
              <ServicesList onSelectService={handleSelectService} />
            </RevealSection>

            {/* Fleet - Fade In since it's wide */}
            <RevealSection variant="fade-in">
              <Fleet onSelect={handleGoToFleet} />
            </RevealSection>

            {/* About Us - Zoom or Slide effect */}
            <RevealSection variant="zoom">
              <AboutUs />
            </RevealSection>

            <RevealSection variant="fade-in">
              <Mission />
            </RevealSection>

            <RevealSection variant="fade-up">
              <WhyChooseUs />
            </RevealSection>

            {/* Who We Serve - Slide In */}
            <RevealSection variant="fade-up">
              <WhoFor />
            </RevealSection>

            <RevealSection variant="fade-up">
              <FAQ />
            </RevealSection>

            <RevealSection variant="zoom">
              <ContactCTA />
            </RevealSection>

            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'booking' && (
          <BookingDashboard initialData={initialBookingData} />
        )}

        {currentView === 'fleet' && (
          <div className="fade-in">
            <FleetPage onBook={handleBookVehicle} />
            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'about' && (
          <div className="fade-in">
            <AboutPage onBook={handleGoToBooking} />
            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'services' && (
          <div className="fade-in">
            <ServicesPage initialServiceId={initialServiceId} />
            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'contact' && (
          <div className="fade-in">
            <ContactPage />
            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'account' && (
          <div className="fade-in pt-40 text-center min-h-screen flex flex-col items-center justify-center">
            <h1 className="text-4xl font-display font-bold">My Account</h1>
            {session ? (
              <>
                <p className="mt-4 text-charcoal/60">Welcome, {session.user.email}</p>
                <button 
                  onClick={handleLogout}
                  className="mt-8 bg-charcoal text-white px-8 py-3 rounded-lg text-sm font-bold tracking-widest uppercase hover:bg-primary transition-colors"
                >
                  Logout
                </button>
              </>
            ) : (
              <p className="mt-4 text-charcoal/60">You are not logged in.</p>
            )}
          </div>
        )}

        {currentView === 'auth' && (
          <div className="fade-in">
            <AuthPage 
              key={authMode}
              initialMode={authMode}
              onAuthSuccess={handleGoToAccount}
            />
          </div>
        )}
      </main>
      <FloatingContactButton />
    </div>
  );
};

export default App;

