  const [isAccountMenuOpen, setIsAccountMenuOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  const navLinks = [
    { label: 'Home', viewId: 'home', action: onGoToHome, icon: 'home' },
    { label: 'About Us', viewId: 'about', action: onGoToAbout, icon: 'info' },
    { label: 'Services', viewId: 'services', action: onGoToServices, icon: 'explore' },
    { label: 'Fleet', viewId: 'fleet', action: onGoToFleet, icon: 'directions_car' },
    { label: 'Contact', viewId: 'contact', action: onGoToContact, icon: 'mail' },
  ];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsAccountMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <>
      {/* Top Navbar: Shared for Desktop and Mobile (CTA Focus) */}
      <nav className="fixed top-6 left-1/2 -translate-x-1/2 z-50 w-[92%] max-w-[1200px]">
        <header className="glass-nav border border-white/20 rounded-xl px-4 md:px-8 py-4 flex items-center justify-between shadow-lg">
          {/* Brand Logo */}
          <button onClick={onGoToHome} className="flex items-center gap-3 group shrink-0">
            <Logo variant="dark" />
          </button>

          {/* Desktop Only Navigation Links */}
          <div className="hidden md:flex items-center gap-6 lg:gap-10">
            {navLinks.map((link) => (
              <button 
                key={link.label}
                onClick={link.action} 
                className={`transition-colors text-[10px] lg:text-xs font-bold tracking-widest uppercase ${
                  currentView === link.viewId ? 'text-primary' : 'text-charcoal/70 hover:text-primary'
                }`}
              >
                {link.label}
              </button>
            ))}
          </div>

          {/* Action Area (Logo, Book Now, Account) */}
          <div className="flex items-center gap-2 md:gap-4">
            <button 
              onClick={onBookNow}
              className="flex items-center justify-center rounded-lg h-10 md:h-11 px-4 md:px-8 bg-primary text-white text-[10px] md:text-xs font-black tracking-[0.2em] hover:bg-charcoal transition-all active:scale-95 shadow-md shadow-primary/20 uppercase"
            >
              Book Now
            </button>

            <div className="relative" ref={menuRef}>
              <button
                onClick={() => setIsAccountMenuOpen(prev => !prev)}
                className="size-9 md:size-10 rounded-full bg-white text-charcoal flex items-center justify-center transition-all shadow-md border border-charcoal/5 active:scale-95 hover:bg-primary hover:text-white"
                aria-label="My Account"
              >
                <span className="material-symbols-outlined !text-xl md:!text-2xl">
                  account_circle
                </span>
              </button>

              {isAccountMenuOpen && (
                <div className="absolute top-full right-0 mt-3 w-48 bg-white rounded-xl shadow-2xl border border-charcoal/5 p-2 z-50 animate-in fade-in zoom-in-95">
                  {session ? (
                    <>
                      <button onClick={() => { onGoToAccount(); setIsAccountMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-medium text-charcoal/80 hover:bg-background-light hover:text-primary rounded-lg transition-colors">
                        <span className="material-symbols-outlined !text-lg">account_circle</span>
                        <span>My Account</span>
                      </button>
                      <button onClick={() => { onLogout(); setIsAccountMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-medium text-charcoal/80 hover:bg-background-light hover:text-primary rounded-lg transition-colors">
                        <span className="material-symbols-outlined !text-lg">logout</span>
                        <span>Logout</span>
                      </button>
                    </>
                  ) : (
                    <>
                      <button onClick={() => { onLogin(); setIsAccountMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-medium text-charcoal/80 hover:bg-background-light hover:text-primary rounded-lg transition-colors">
                        <span className="material-symbols-outlined !text-lg">login</span>
                        <span>Login</span>
                      </button>
                      <button onClick={() => { onSignUp(); setIsAccountMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-medium text-charcoal/80 hover:bg-background-light hover:text-primary rounded-lg transition-colors">
                        <span className="material-symbols-outlined !text-lg">person_add</span>
                        <span>Sign Up</span>
                      </button>
                    </>
                  )}
                </div>
              )}
            </div>
          </div>
        </header>
      </nav>

      {/* Mobile Bottom Navigation Bar (Hidden on md screens and up) */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 z-50 bg-white/95 backdrop-blur-md border-t border-charcoal/5 shadow-[0_-4px_20px_rgba(0,0,0,0.05)] pb-[env(safe-area-inset-bottom,12px)]">
        <div className="flex justify-around items-center h-16 px-2">
          {navLinks.map((link) => {
            const isActive = currentView === link.viewId;
            return (
              <button
                key={link.label}
                onClick={link.action}
                className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all duration-300 active:scale-90 ${
                  isActive ? 'text-primary' : 'text-charcoal/40'
                }`}
              >
                <span className={`material-symbols-outlined !text-[24px] ${isActive ? 'fill-1' : ''}`}>
                  {link.icon}
                </span>
                <span className="text-[9px] font-black uppercase tracking-widest leading-none">
                  {link.label.split(' ')[0]}
                </span>
              </button>
            );
          })}
        </div>
      </nav>
    </>
  );
};

export default Navbar;

