import { supabase } from './lib/supabaseClient';
import { Session } from '@supabase/supabase-js';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import BookingBar, { SearchParams } from './components/BookingBar';
import HomeSearchResults from './components/HomeSearchResults';
import Experience from './components/Experience';
import ServicesList from './components/ServicesList';
import Fleet from './components/Fleet';
import AboutUs from './components/AboutUs';
import Mission from './components/Mission';
import WhyChooseUs from './components/WhyChooseUs';
import WhoFor from './components/WhoFor';
import FAQ from './components/FAQ';
import ContactCTA from './components/ContactCTA';
import Footer from './components/Footer';
import BookingDashboard from './components/BookingDashboard';
import FleetPage from './components/FleetPage';
import AboutPage from './components/AboutPage';
import ServicesPage from './components/ServicesPage';
import ContactPage from './components/ContactPage';
import RevealSection from './components/RevealSection';
import AuthPage from './components/AuthPage';
import FloatingContactButton from './components/FloatingContactButton';
import AccountPage from './components/AccountPage';

interface VehicleResult {
  vehicle: any;
  totalPrice: number;
}

const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [currentView, setCurrentView] = useState<'home' | 'booking' | 'fleet' | 'about' | 'services' | 'contact' | 'account' | 'auth'>('home');
  const [targetSection, setTargetSection] = useState<string | null>(null);
  const [initialBookingData, setInitialBookingData] = useState<any>(null);
  const [initialServiceId, setInitialServiceId] = useState<string | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');

  // Data State for Home Search
  const [vehicles, setVehicles] = useState<any[]>([]);
  const [pricingRules, setPricingRules] = useState<any[]>([]);
  const [publicHolidays, setPublicHolidays] = useState<string[]>([]);
  const [homeSearchResults, setHomeSearchResults] = useState<VehicleResult[]>([]);
  const [currentSearchParams, setCurrentSearchParams] = useState<SearchParams | null>(null);

  // Auth Listener
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        setSession(session);
        if (_event === 'SIGNED_IN') {
            setCurrentView('account');
        }
        if (_event === 'SIGNED_OUT') {
            setCurrentView('home');
        }
    });

    return () => subscription.unsubscribe();
  }, []);

  // Fetch Data on Load
  useEffect(() => {
    const fetchSystemData = async () => {
      try {
        const [v, r, h] = await Promise.all([
          supabase.from('vehicles').select('*'),
          supabase.from('pricing_rules').select('*').eq('is_active', true),
          supabase.from('public_holidays').select('holiday_date')
        ]);
        setVehicles(v.data || []);
        setPricingRules(r.data || []);
        setPublicHolidays((h.data || []).map((x: any) => x.holiday_date));
      } catch (err) {
        console.error("Error fetching initial data", err);
      }
    };
    fetchSystemData();
  }, []);

  const handleGoToBooking = () => {
    setInitialBookingData(null); 
    setCurrentView('booking');
    window.scrollTo(0, 0);
  };

  const handleBookVehicle = (vehicleId: string) => {
    // If we have search params from home search, pass them along
    if (currentSearchParams) {
      setInitialBookingData({
        pickup: currentSearchParams.pickup,
        dropoff: currentSearchParams.dropoff,
        date: currentSearchParams.date,
        time: currentSearchParams.time,
        passengers: currentSearchParams.passengers,
        vehicleId: vehicleId
      });
    } else {
      setInitialBookingData({ vehicleId });
    }
    setCurrentView('booking');
    window.scrollTo(0, 0);
  };

  const handleGoToHome = () => {
    setCurrentView('home');
    window.scrollTo(0, 0);
  };

  const handleGoToFleet = () => {
    setCurrentView('fleet');
    window.scrollTo(0, 0);
  };

  const handleGoToAbout = () => {
    setCurrentView('about');
    window.scrollTo(0, 0);
  };

  const handleGoToServices = () => {
    setInitialServiceId(null); 
    setCurrentView('services');
    window.scrollTo(0, 0);
  };

  const handleGoToContact = () => {
    setCurrentView('contact');
    window.scrollTo(0, 0);
  };

  const handleGoToAccount = () => {
    if (session) {
      setCurrentView('account');
      window.scrollTo(0, 0);
    } else {
      handleLogin();
    }
  };

  const handleLogin = () => {
    setAuthMode('login');
    setCurrentView('auth');
    window.scrollTo(0,0);
  };

  const handleSignUp = () => {
    setAuthMode('signup');
    setCurrentView('auth');
    window.scrollTo(0,0);
  };

  const handleLogout = async () => {
    const { error } = await supabase.auth.signOut();
    if (error) {
        console.error("Error signing out:", error);
    }
  };

  const handleSelectService = (serviceId: string) => {
    setInitialServiceId(serviceId);
    setCurrentView('services');
    window.scrollTo(0, 0);
  };

  const handleGoToSection = (sectionId: string) => {
    if (currentView !== 'home') {
      setTargetSection(sectionId);
      setCurrentView('home');
    } else {
      setTimeout(() => {
        const element = document.getElementById(sectionId);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        }
      }, 100);
    }
  };

  // Perform Search Logic (Client Side Calculation)
  const handleHomeSearch = (params: SearchParams) => {
    setCurrentSearchParams(params);

    // Filter eligible vehicles
    const eligibleVehicles = vehicles.filter(v => v.capacity_seats >= params.passengers);

    if (eligibleVehicles.length === 0) {
      alert("No vehicles available for this number of passengers.");
      return;
    }

    const pickupDate = new Date(`${params.date}T${params.time}`);
    const getRuleValue = (type: string) => pricingRules.find(r => r.rule_type === type)?.value_cents || 0;

    // Calculate Surcharges
    const basePrice = getRuleValue('BASE_FEE');

    let weekendSurcharge = 0;
    const weekendRule = pricingRules.find(r => r.rule_type === 'WEEKEND');
    if (weekendRule && weekendRule.days_of_week && weekendRule.days_of_week.includes(pickupDate.getDay())) {
        weekendSurcharge = weekendRule.value_cents;
    }

    let afterHoursSurcharge = 0;
    const timeStr = `${params.time}:00`;
    const afterHoursRule = pricingRules.find(r => r.rule_type === 'AFTER_HOURS');
    if (afterHoursRule && afterHoursRule.start_time && afterHoursRule.end_time) {
        const isOvernight = afterHoursRule.start_time > afterHoursRule.end_time;
        if (isOvernight ? (timeStr >= afterHoursRule.start_time || timeStr < afterHoursRule.end_time) : (timeStr >= afterHoursRule.start_time && timeStr < afterHoursRule.end_time)) {
            afterHoursSurcharge = afterHoursRule.value_cents;
        }
    }

    let holidaySurcharge = publicHolidays.includes(params.date) ? getRuleValue('PUBLIC_HOLIDAY') : 0;

    // Calculate per vehicle
    const results = eligibleVehicles.map(v => {
      const distanceCost = (v.price_per_km_cents * params.distanceKm);
      const totalCents = basePrice + distanceCost + weekendSurcharge + afterHoursSurcharge + holidaySurcharge;

      return {
        vehicle: v,
        totalPrice: totalCents / 100
      };
    });

    setHomeSearchResults(results);

    // Scroll to results
    setTimeout(() => {
      const el = document.getElementById('search-results');
      if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 200);
  };

  // Effect to handle scrolling after view changes to 'home'
  useEffect(() => {
    if (currentView === 'home' && targetSection) {
      setTimeout(() => {
        const element = document.getElementById(targetSection);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        }
        setTargetSection(null);
      }, 100);
    }
  }, [currentView, targetSection]);

  return (
    <div className="relative min-h-screen bg-background-light">
      <Navbar 
        session={session}
        currentView={currentView}
        onBookNow={handleGoToBooking} 
        onGoToFleet={handleGoToFleet}
        onGoToHome={handleGoToHome}
        onGoToAbout={handleGoToAbout}
        onGoToServices={handleGoToServices}
        onGoToContact={handleGoToContact}
        onLogin={handleLogin}
        onSignUp={handleSignUp}
        onLogout={handleLogout}
        onGoToAccount={handleGoToAccount}
        onGoToSection={handleGoToSection}
      />

      <main className="pt-0">
        {currentView === 'home' && (
          <div className="fade-in">
            <Hero onExplore={handleGoToFleet} onSeeStory={handleGoToAbout} />

            {/* Search Bar - Reveals with slight delay */}
            <div className="relative z-30 px-6 max-w-[1100px] mx-auto -mt-16">
              <RevealSection delay={200} variant="fade-up">
                <BookingBar onSearch={handleHomeSearch} />
              </RevealSection>
            </div>

            {/* Search Results Section */}
            <div className="mt-12">
               {homeSearchResults.length > 0 && (
                   <RevealSection variant="fade-up">
                       <HomeSearchResults results={homeSearchResults} onBook={handleBookVehicle} />
                   </RevealSection>
               )}
            </div>

            {/* "Meticulously Crafted Service" Section */}
            <RevealSection variant="fade-up">
              <Experience />
            </RevealSection>

            {/* Services - Staggered Slide In effect could be simulated by container animation */}
            <RevealSection variant="fade-up">
              <ServicesList onSelectService={handleSelectService} />
            </RevealSection>

            {/* Fleet - Fade In since it's wide */}
            <RevealSection variant="fade-in">
              <Fleet onSelect={handleGoToFleet} />
            </RevealSection>

            {/* About Us - Zoom or Slide effect */}
            <RevealSection variant="zoom">
              <AboutUs />
            </RevealSection>

            <RevealSection variant="fade-in">
              <Mission />
            </RevealSection>

            <RevealSection variant="fade-up">
              <WhyChooseUs />
            </RevealSection>

            {/* Who We Serve - Slide In */}
            <RevealSection variant="fade-up">
              <WhoFor />
            </RevealSection>

            <RevealSection variant="fade-up">
              <FAQ />
            </RevealSection>

            <RevealSection variant="zoom">
              <ContactCTA />
            </RevealSection>

            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'booking' && (
          <BookingDashboard initialData={initialBookingData} />
        )}

        {currentView === 'fleet' && (
          <div className="fade-in">
            <FleetPage onBook={handleBookVehicle} />
            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'about' && (
          <div className="fade-in">
            <AboutPage onBook={handleGoToBooking} />
            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'services' && (
          <div className="fade-in">
            <ServicesPage initialServiceId={initialServiceId} />
            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'contact' && (
          <div className="fade-in">
            <ContactPage />
            <Footer onGoToBooking={handleGoToBooking} onGoToFleet={handleGoToFleet} onGoToContact={handleGoToContact} />
          </div>
        )}

        {currentView === 'account' && (
          <AccountPage session={session} onLogout={handleLogout} />
        )}

        {currentView === 'auth' && (
          <div className="fade-in">
            <AuthPage 
              key={authMode}
              initialMode={authMode}
              onAuthSuccess={handleGoToAccount}
            />
          </div>
        )}
      </main>

      { /* Hide floating button when on account page on mobile */ }
      { !(currentView === 'account') && <FloatingContactButton /> }
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Session } from '@supabase/supabase-js';
import Logo from './Logo';

interface NavbarProps {
  session: Session | null;
  currentView?: string;
  onBookNow: () => void;
  onGoToFleet: () => void;
  onGoToHome: () => void;
  onGoToAbout: () => void;
  onGoToServices: () => void;
  onGoToContact: () => void;
  onLogin: () => void;
  onSignUp: () => void;
  onLogout: () => void;
  onGoToAccount: () => void;
  onGoToSection: (sectionId: string) => void;
}

const Navbar: React.FC<NavbarProps> = ({ 
  session,
  currentView,
  onBookNow, 
  onGoToFleet, 
  onGoToHome, 
  onGoToAbout, 
  onGoToServices, 
  onGoToContact,
  onLogin,
  onSignUp,
  onLogout,
  onGoToAccount,
  onGoToSection 
}) => {
  const [isAccountMenuOpen, setIsAccountMenuOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  const desktopNavLinks = [
    { label: 'Home', viewId: 'home', action: onGoToHome },
    { label: 'About Us', viewId: 'about', action: onGoToAbout },
    { label: 'Services', viewId: 'services', action: onGoToServices },
    { label: 'Fleet', viewId: 'fleet', action: onGoToFleet },
    { label: 'Contact', viewId: 'contact', action: onGoToContact },
  ];

  const mobileNavLinks = [
    { label: 'Home', viewId: 'home', action: onGoToHome, icon: 'home' },
    { label: 'Services', viewId: 'services', action: onGoToServices, icon: 'apps' },
    { label: 'Activity', viewId: 'account', action: onGoToAccount, icon: 'receipt_long' },
    { label: 'Account', viewId: 'account', action: onGoToAccount, icon: 'person' },
  ];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsAccountMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const isAccountView = currentView === 'account' || currentView === 'auth';

  return (
    <>
      {/* Top Navbar: Shared for Desktop and Mobile (CTA Focus) */}
      <nav className={`fixed top-6 left-1/2 -translate-x-1/2 z-50 w-[92%] max-w-[1200px] transition-opacity duration-300 ${isAccountView ? 'opacity-0 pointer-events-none md:opacity-100 md:pointer-events-auto' : ''}`}>
        <header className="glass-nav border border-white/20 rounded-xl px-4 md:px-8 py-4 flex items-center justify-between shadow-lg">
          {/* Brand Logo */}
          <button onClick={onGoToHome} className="flex items-center gap-3 group shrink-0">
            <Logo variant="dark" />
          </button>

          {/* Desktop Only Navigation Links */}
          <div className="hidden md:flex items-center gap-6 lg:gap-10">
            {desktopNavLinks.map((link) => (
              <button 
                key={link.label}
                onClick={link.action} 
                className={`transition-colors text-[10px] lg:text-xs font-bold tracking-widest uppercase ${
                  currentView === link.viewId ? 'text-primary' : 'text-charcoal/70 hover:text-primary'
                }`}
              >
                {link.label}
              </button>
            ))}
          </div>

          {/* Action Area (Logo, Book Now, Account) */}
          <div className="flex items-center gap-2 md:gap-4">
            <button 
              onClick={onBookNow}
              className="flex items-center justify-center rounded-lg h-10 md:h-11 px-4 md:px-8 bg-primary text-white text-[10px] md:text-xs font-black tracking-[0.2em] hover:bg-charcoal transition-all active:scale-95 shadow-md shadow-primary/20 uppercase"
            >
              Book Now
            </button>

            <div className="relative" ref={menuRef}>
              <button
                onClick={() => setIsAccountMenuOpen(prev => !prev)}
                className="size-9 md:size-10 rounded-full bg-white text-charcoal flex items-center justify-center transition-all shadow-md border border-charcoal/5 active:scale-95 hover:bg-primary hover:text-white"
                aria-label="My Account"
              >
                <span className="material-symbols-outlined !text-xl md:!text-2xl">
                  account_circle
                </span>
              </button>

              {isAccountMenuOpen && (
                <div className="absolute top-full right-0 mt-3 w-48 bg-white rounded-xl shadow-2xl border border-charcoal/5 p-2 z-50 animate-in fade-in zoom-in-95">
                  {session ? (
                    <>
                      <button onClick={() => { onGoToAccount(); setIsAccountMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-medium text-charcoal/80 hover:bg-background-light hover:text-primary rounded-lg transition-colors">
                        <span className="material-symbols-outlined !text-lg">account_circle</span>
                        <span>My Account</span>
                      </button>
                      <button onClick={() => { onLogout(); setIsAccountMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-medium text-charcoal/80 hover:bg-background-light hover:text-primary rounded-lg transition-colors">
                        <span className="material-symbols-outlined !text-lg">logout</span>
                        <span>Logout</span>
                      </button>
                    </>
                  ) : (
                    <>
                      <button onClick={() => { onLogin(); setIsAccountMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-medium text-charcoal/80 hover:bg-background-light hover:text-primary rounded-lg transition-colors">
                        <span className="material-symbols-outlined !text-lg">login</span>
                        <span>Login</span>
                      </button>
                      <button onClick={() => { onSignUp(); setIsAccountMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-medium text-charcoal/80 hover:bg-background-light hover:text-primary rounded-lg transition-colors">
                        <span className="material-symbols-outlined !text-lg">person_add</span>
                        <span>Sign Up</span>
                      </button>
                    </>
                  )}
                </div>
              )}
            </div>
          </div>
        </header>
      </nav>

      {/* Mobile Bottom Navigation Bar (Hidden on md screens and up) */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 z-50 bg-white border-t border-gray-200 pb-[env(safe-area-inset-bottom,12px)]">
        <div className="flex justify-around items-start h-16 px-2 pt-2">
          {mobileNavLinks.map((link) => {
            const isActive = currentView === link.viewId;
            return (
              <button
                key={link.label}
                onClick={link.action}
                className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all duration-300 active:scale-95 ${
                  isActive ? 'text-charcoal' : 'text-gray-400'
                }`}
                aria-current={isActive ? 'page' : undefined}
              >
                <span className="material-symbols-outlined !text-[26px]">
                  {link.icon}
                </span>
                <span className="text-xs font-semibold leading-none">
                  {link.label}
                </span>
              </button>
            );
          })}
        </div>
      </nav>
    </>
  );
};

