  const [pickup, setPickup] = useState(initialData?.pickup?.address || '');
  const [dropoff, setDropoff] = useState(initialData?.dropoff?.address || '');
  const [pickupPlaceId, setPickupPlaceId] = useState<string | null>(null);
  const [dropoffPlaceId, setDropoffPlaceId] = useState<string | null>(null);
  const [pickupDate, setPickupDate] = useState(initialData?.date || '');
  const [pickupTime, setPickupTime] = useState(initialData?.time || '');
  const [isReturnTrip, setIsReturnTrip] = useState(false);
  const [returnDate, setReturnDate] = useState('');
  const [returnTime, setReturnTime] = useState('');
  const [numPassengers, setNumPassengers] = useState(initialData?.passengers || 1);
  const [addBabySeat, setAddBabySeat] = useState(false);
  const [addTrailer, setAddTrailer] = useState(false);
  const [meetAndGreet, setMeetAndGreet] = useState(false);
  const [selectedVehicleId, setSelectedVehicleId] = useState<string | null>(initialData?.vehicleId || null);
  const [viewingVehicle, setViewingVehicle] = useState<Vehicle | null>(null);
  const [firstName, setFirstName] = useState('');
  const [surname, setSurname] = useState('');
  const [email, setEmail] = useState('');
  const [countryCode, setCountryCode] = useState('+27');
  const [phone, setPhone] = useState('');
  const [comments, setComments] = useState('');
  const [bookingId, setBookingId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const pickupInputRef = useRef<HTMLInputElement>(null);
  const dropoffInputRef = useRef<HTMLInputElement>(null);

  const getMinDate = () => {
    const d = new Date();
    d.setDate(d.getDate() + 2);
    return d.toISOString().split('T')[0];
  };

  const minDate = getMinDate();

  useEffect(() => {
    // Dynamically load the Google Maps script
    const GOOGLE_MAPS_API_KEY = (import.meta as any).env.VITE_GOOGLE_MAPS_API_KEY;
    if (!GOOGLE_MAPS_API_KEY) {
        console.error("VITE_GOOGLE_MAPS_API_KEY is not configured.");
        setError("Map service is unavailable. Please refresh or contact support.");
        return;
    }

    const scriptId = 'google-maps-script';
    if (document.getElementById(scriptId)) {
        return;
    }

    const script = document.createElement('script');
    script.id = scriptId;
    script.src = `https://maps.googleapis.com/maps/api/js?key=${GOOGLE_MAPS_API_KEY}&libraries=places`;
    script.async = true;
    script.defer = true;
    document.body.appendChild(script);

    script.onload = () => {
        // Initialize autocomplete fields
        if (pickupInputRef.current && window.google) {
            const autocomplete = new window.google.maps.places.Autocomplete(pickupInputRef.current, {
                componentRestrictions: { country: "za" },
                fields: ["place_id", "formatted_address"],
            });
            autocomplete.addListener("place_changed", () => {
                const place = autocomplete.getPlace();
                setPickup(place.formatted_address || '');
                setPickupPlaceId(place.place_id || null);
            });
        }
        if (dropoffInputRef.current && window.google) {
            const autocomplete = new window.google.maps.places.Autocomplete(dropoffInputRef.current, {
