    if (diffHours < 48) {
        setError('Bookings must be made at least 48 hours (2 days) in advance.');
        setIsLoading(false);
        return;
    }

    const eligibleVehicles = vehicles.filter(v => v.capacity_seats >= numPassengers);
    if (eligibleVehicles.length === 0) {
        setError('No vehicles available for selected passengers.');
        setIsLoading(false);
        return;
    }

    try {
        const quotePromises = eligibleVehicles.map(async (vehicle) => {
            const { data, error } = await supabase.functions.invoke('get-quote', {
                body: {
                    vehicleId: vehicle.id,
                    pickupPlaceId,
                    dropoffPlaceId,
                    pickupTimestamp: `${pickupDate}T${pickupTime}`,
                    isReturnTrip,
                    addBabySeat,
                    addTrailer
                }
            });

            if (error) throw new Error(error.message);

            if (data.error) throw new Error(data.error);

            if (data.requiresEnquiry) {
                throw new Error(data.reason || 'This trip is outside our standard service area and requires a special enquiry. Please contact us directly.');
            }
            return { vehicle, quote: data };
        });

        const calculatedQuotes = await Promise.all(quotePromises);
        setVehicleQuotes(calculatedQuotes);
        setCurrentStep(2);
        window.scrollTo(0, 0);

    } catch (err: any) {
        setError(err.message);
    } finally {
        setIsLoading(false);
    }
  };

