            <div>
                <h2 className="text-lg font-bold text-charcoal mb-2">No. of Passengers</h2>
                <div className="relative"><select value={numPassengers} onChange={e => setNumPassengers(parseInt(e.target.value))} className="w-full bg-gray-50 border-none rounded-xl h-14 px-4 text-sm focus:ring-1 focus:ring-accent-gold font-medium text-charcoal appearance-none">{[...Array(13).keys()].map(i => <option key={i+1} value={i+1}>{i+1} Passenger{i > 0 ? 's' : ''}</option>)}</select><span className="material-symbols-outlined absolute right-4 top-1/2 -translate-y-1/2 text-charcoal/50 pointer-events-none">expand_more</span></div>
            </div>
            <div className="flex gap-4 items-center">
                 <label className="flex items-center gap-2 cursor-pointer p-3 rounded-lg border border-gray-200 hover:border-accent-gold transition-colors flex-1"><input type="checkbox" checked={addBabySeat} onChange={e => setAddBabySeat(e.target.checked)} className="text-accent-gold focus:ring-accent-gold rounded" /><span className="text-xs font-bold text-charcoal">Baby Seat</span></label>
                 <label className="flex items-center gap-2 cursor-pointer p-3 rounded-lg border border-gray-200 hover:border-accent-gold transition-colors flex-1"><input type="checkbox" checked={meetAndGreet} onChange={e => setMeetAndGreet(e.target.checked)} className="text-accent-gold focus:ring-accent-gold rounded" /><span className="text-xs font-bold text-charcoal">Meet & Greet</span></label>
            </div>
            <button onClick={handleGetQuotes} disabled={isLoading} className="w-full h-14 bg-charcoal text-white rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-black transition-all shadow-lg text-sm tracking-widest uppercase disabled:opacity-50">{isLoading ? 'Calculating Quotes...' : 'Next: Choose Vehicle'}</button>
        </div>
    </div>
  );

  const renderVehicleDetailsPopup = () => {
    if (!viewingVehicle) return null;
    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setViewingVehicle(null)}>
            <div className="bg-white rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto relative shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
                <button onClick={() => setViewingVehicle(null)} className="absolute top-4 right-4 z-10 size-10 bg-white/90 backdrop-blur rounded-full flex items-center justify-center hover:bg-gray-100 transition-colors shadow-sm"><span className="material-symbols-outlined text-charcoal">close</span></button>
                <div className="h-64 w-full relative bg-gray-100"><img src={viewingVehicle.hero_image_url} alt={viewingVehicle.name} className="w-full h-full object-cover" /><div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div><div className="absolute bottom-6 left-6 text-white"><h2 className="text-3xl font-display font-bold">{viewingVehicle.name.split('|')[0]}</h2><p className="opacity-90 text-sm">{viewingVehicle.name.split('|')[1] || 'Luxury Vehicle'}</p></div></div>
                <div className="p-8"><div className="flex gap-4 mb-8 border-b border-gray-100 pb-8"><div className="flex flex-col items-center justify-center bg-gray-50 w-24 py-3 rounded-xl border border-gray-100"><span className="material-symbols-outlined text-charcoal/60 mb-1">person</span><span className="text-xs font-bold text-charcoal">{viewingVehicle.capacity_seats} Seats</span></div><div className="flex flex-col items-center justify-center bg-gray-50 w-24 py-3 rounded-xl border border-gray-100"><span className="material-symbols-outlined text-charcoal/60 mb-1">luggage</span><span className="text-xs font-bold text-charcoal">{viewingVehicle.capacity_bags} Bags</span></div></div>
                <div className="space-y-6">{viewingVehicle.details?.features && (<div><h3 className="font-bold text-charcoal mb-4 flex items-center gap-2"><span className="material-symbols-outlined text-accent-gold">verified</span> Vehicle Features</h3><ul className="grid grid-cols-1 md:grid-cols-2 gap-3">{(viewingVehicle.details).features.map((feature, i) => (<li key={i} className="text-sm text-charcoal/70 flex items-start gap-3 bg-gray-50 p-3 rounded-lg"><span className="material-symbols-outlined !text-base text-green-600 mt-0.5">check_circle</span>{feature}</li>))}</ul></div>)}{viewingVehicle.details?.idealFor && (<div><h3 className="font-bold text-charcoal mb-4 mt-6 flex items-center gap-2"><span className="material-symbols-outlined text-accent-gold">star</span> Perfect For</h3><div className="flex flex-wrap gap-2">{(viewingVehicle.details).idealFor.map((item, i) => (<span key={i} className="text-xs font-bold bg-white text-charcoal px-4 py-2 rounded-full border border-gray-200 shadow-sm uppercase tracking-wide">{item}</span>))}</div></div>)}</div>
                <div className="mt-8 pt-6 border-t border-gray-100"><button onClick={() => { setSelectedVehicleId(viewingVehicle.id); setViewingVehicle(null); }} className="w-full bg-charcoal text-white h-14 rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-black transition-all shadow-lg flex items-center justify-center gap-2">Select This Vehicle</button></div></div>
            </div>
        </div>
    );
  };

  const renderChooseRide = () => {
    return (
        <div className="space-y-6">
            <h1 className="text-3xl font-display font-bold text-charcoal">Select Your Vehicle</h1>
            <div className="space-y-6">{vehicleQuotes.map(({vehicle, quote}, index) => { const isSelected = selectedVehicleId === vehicle.id; const nameParts = vehicle.name.split('|'); const mainName = nameParts[0]?.trim() || vehicle.name; const subName = nameParts[1] ? nameParts[1].trim() : "Luxury Vehicle"; const isPopular = index === 0; return (<div key={vehicle.id} onClick={() => setSelectedVehicleId(vehicle.id)} className={`flex flex-col md:flex-row bg-white rounded-2xl overflow-hidden border-2 cursor-pointer transition-all duration-300 shadow-md hover:shadow-xl ${isSelected ? 'border-accent-gold ring-1 ring-accent-gold' : 'border-transparent'}`}><div className="w-full md:w-1/3 bg-booking-dark relative min-h-[200px] md:min-h-0"><img src={vehicle.hero_image_url} alt={mainName} className="absolute inset-0 w-full h-full object-cover"/><div className="absolute inset-0 bg-black/20"></div></div><div className="w-full md:w-2/3 p-6 flex flex-col justify-between"><div className="flex justify-between items-start"><div><div className="flex items-center gap-2 mb-1"><h2 className="text-xl font-bold text-charcoal">{mainName}</h2>{isPopular && <span className="bg-gray-100 text-charcoal/60 text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-wider">Popular</span>}</div><p className="text-charcoal/50 text-sm">{subName}</p></div><div className="text-right"><div className="text-2xl font-black text-charcoal">R{quote.totalPrice.toFixed(2)}</div><div className="text-[10px] text-charcoal/40 font-bold uppercase tracking-wider">Total Price</div></div></div><div className="flex gap-4 mt-6 mb-6"><div className="flex items-center gap-2 bg-gray-50 px-3 py-2 rounded-lg text-charcoal/70"><span className="material-symbols-outlined !text-lg">person</span><span className="text-xs font-bold">{vehicle.capacity_seats}</span></div><div className="flex items-center gap-2 bg-gray-50 px-3 py-2 rounded-lg text-charcoal/70"><span className="material-symbols-outlined !text-lg">luggage</span><span className="text-xs font-bold">{vehicle.capacity_bags}</span></div></div><div className="flex items-center justify-between mt-auto"><button onClick={(e) => { e.stopPropagation(); setViewingVehicle(vehicle); }} className="text-accent-gold text-xs font-bold hover:underline">Vehicle details</button><button className={`px-8 py-3 rounded-lg text-sm font-bold tracking-widest uppercase transition-all ${isSelected ? 'bg-accent-gold text-white shadow-lg' : 'bg-charcoal text-white hover:bg-black'}`}>{isSelected ? <span className="flex items-center gap-2"><span className="material-symbols-outlined !text-lg">check</span> Selected</span> : 'Select'}</button></div></div></div>);})}</div>
        </div>
    );
  };
  const renderPassengerDetails = () => {
    return (
     <div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100"><h1 className="text-2xl font-display font-bold text-charcoal mb-6">Passenger Details</h1><div className="space-y-4"><div className="grid grid-cols-2 gap-4"><div><label className="block text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1.5 ml-1">First Name</label><input type="text" placeholder="e.g. John" value={firstName} onChange={e => setFirstName(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl h-12 text-sm focus:ring-1 focus:ring-accent-gold font-medium"/></div><div><label className="block text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1.5 ml-1">Surname</label><input type="text" placeholder="e.g. Doe" value={surname} onChange={e => setSurname(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl h-12 text-sm focus:ring-1 focus:ring-accent-gold font-medium"/></div></div><div><label className="block text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1.5 ml-1">Email Address</label><input type="email" placeholder="john@example.com" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl h-12 text-sm focus:ring-1 focus:ring-accent-gold font-medium"/></div><div><label className="block text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1.5 ml-1">Phone Number</label><div className="flex gap-3"><select value={countryCode} onChange={e => setCountryCode(e.target.value)} className="bg-gray-50 border-none rounded-xl h-12 text-sm focus:ring-1 focus:ring-accent-gold font-medium w-24"><option value="+27">ZA +27</option><option value="+1">US +1</option><option value="+44">UK +44</option></select><input type="tel" placeholder="83 123 4567" value={phone} onChange={e => setPhone(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl h-12 text-sm focus:ring-1 focus:ring-accent-gold font-medium"/></div></div><div><label className="block text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1.5 ml-1">Comments / Flight Number</label><textarea rows={3} placeholder="Flight details or special requests..." value={comments} onChange={e => setComments(e.target.value)} className="w-full bg-gray-50 border-none rounded-xl text-sm focus:ring-1 focus:ring-accent-gold font-medium p-4"/></div></div></div>);
  };
  const renderConfirmation = () => {
    return (<div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100"><h1 className="text-2xl font-display font-bold text-charcoal mb-6">Review & Confirm Booking</h1><div className="space-y-6"><p className="text-sm text-charcoal/60 leading-relaxed bg-gray-50 p-4 rounded-xl border border-gray-100">Please review your trip details. This is a final confirmation. Payment will be processed upon submission.</p><p className="text-xs text-charcoal/60 leading-relaxed">By clicking "Confirm Booking", you agree to our Terms of Service.</p></div></div>);
  };
  const renderSuccess = () => {
    return (<div className="text-center py-12 bg-white rounded-2xl shadow-xl"><div className="size-24 rounded-full bg-green-50 text-green-600 flex items-center justify-center mx-auto mb-6"><span className="material-symbols-outlined !text-5xl">check_circle</span></div><h1 className="text-3xl font-display font-bold text-charcoal mb-4">Booking Confirmed!</h1><p className="text-charcoal/60 mb-8 max-w-sm mx-auto">Your booking (Ref: <span className="font-bold text-charcoal">{bookingId?.substring(0,8).toUpperCase()}</span>) has been confirmed. We've sent details to {email}.</p><button onClick={startNewBooking} className="bg-charcoal text-white px-8 py-3 rounded-xl text-sm font-bold tracking-widest uppercase hover:bg-black transition-colors shadow-lg">Make Another Booking</button></div>);
  };

  const renderTripSummary = () => {
    const selectedQuote = vehicleQuotes.find(vq => vq.vehicle.id === selectedVehicleId); let btnText = "Next"; let btnAction: () => void = nextStep; let btnDisabled = false; if (currentStep === 2) { btnText = "Next: Details"; btnDisabled = !selectedVehicleId; } else if (currentStep === 3) { btnText = "Next: Confirm"; btnDisabled = !firstName || !surname || !email || !phone; } else if (currentStep === 4) { btnText = isLoading ? "Confirming..." : "Confirm Booking"; btnAction = handleConfirmBooking; btnDisabled = isLoading; }
    return (<div className="bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden sticky top-24"><div className="p-4 bg-white border-b border-gray-100 z-20 relative flex justify-between items-center"><h3 className="font-bold text-lg text-charcoal">Booking Summary</h3></div><div className="p-6 space-y-6">{selectedQuote ? (<div className="flex items-center gap-4"><div className="size-14 bg-white rounded-xl p-1 border border-gray-100 flex items-center justify-center shadow-sm"><img src={selectedQuote.vehicle.hero_image_url} alt="Vehicle" className="w-full h-full object-contain" /></div><div className="flex-1"><h4 className="font-bold text-sm text-charcoal">{selectedQuote.vehicle.name.split('|')[0]}</h4><p className="text-[10px] text-charcoal/50">{selectedQuote.vehicle.name.split('|')[1] || 'Luxury Class'} • {numPassengers} Passengers</p></div><div className="text-right"><span className="font-bold text-sm text-accent-gold">R{selectedQuote.quote.totalPrice.toFixed(2)}</span></div></div>) : (<div className="flex items-center gap-4 opacity-50"><div className="size-14 bg-gray-100 rounded-xl flex items-center justify-center"><span className="material-symbols-outlined text-charcoal/30">directions_car</span></div><div><h4 className="font-bold text-sm text-charcoal">No Vehicle Selected</h4><p className="text-[10px] text-charcoal/50">Please select a vehicle</p></div></div>)}<hr className="border-gray-100" /><div className="relative pl-4"><div className="absolute top-2 left-0 bottom-4 w-0.5 bg-gray-200 border-l border-dashed border-gray-300"></div><div className="mb-6 relative"><div className="absolute -left-[5px] top-1.5 size-2.5 rounded-full bg-accent-gold ring-2 ring-white"></div><p className="text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1">Pick-up</p><p className="text-sm font-bold text-charcoal leading-tight mb-1 truncate">{pickup || '...'}</p><p className="text-xs text-charcoal/50">{pickupDate} • {pickupTime}</p></div><div className="relative"><div className="absolute -left-[5px] top-1.5 size-2.5 rounded-full bg-charcoal ring-2 ring-white"></div><p className="text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-1">Drop-off</p><p className="text-sm font-bold text-charcoal leading-tight truncate">{dropoff || '...'}</p></div></div>{(addBabySeat || meetAndGreet) && (<div className="pt-2"><p className="text-[10px] font-bold text-charcoal/40 uppercase tracking-widest mb-2">ADD-ONS</p><div className="flex flex-wrap gap-2">{addBabySeat && <span className="px-3 py-1 bg-gray-100 rounded-full text-[10px] font-bold text-charcoal/70">Baby Seat</span>}{meetAndGreet && <span className="px-3 py-1 bg-gray-100 rounded-full text-[10px] font-bold text-charcoal/70">Meet & Greet</span>}</div></div>)}<div className="space-y-3 pt-2"><button onClick={btnAction} disabled={btnDisabled} className="w-full h-12 bg-charcoal text-white rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-black transition-all shadow-lg text-xs tracking-widest uppercase disabled:opacity-50 disabled:cursor-not-allowed group">{btnText}{!isLoading && <span className="material-symbols-outlined group-hover:translate-x-1 transition-transform !text-base">arrow_forward</span>}</button>{currentStep > 1 && (<button onClick={prevStep} className="w-full h-12 bg-white border border-gray-200 text-charcoal rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-gray-50 transition-all text-xs tracking-widest uppercase">Back</button>)}</div></div></div>);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center pt-40 pb-12 font-sans px-4">
       <div className="w-full max-w-6xl mx-auto">
          {currentStep <= 4 && renderProgressBar()}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
             <div className={`${currentStep === 5 ? 'lg:col-span-3 max-w-3xl mx-auto' : 'lg:col-span-2'}`}>
                 {currentStep === 1 && renderRideDetails()}
                 {currentStep === 2 && renderChooseRide()}
                 {currentStep === 3 && renderPassengerDetails()}
                 {currentStep === 4 && renderConfirmation()}
                 {currentStep === 5 && renderSuccess()}
                 {error && (<div className="bg-red-50 border border-red-100 p-4 rounded-xl mt-4 flex gap-3 items-start animate-in fade-in slide-in-from-top-2"><span className="material-symbols-outlined text-red-500 !text-lg mt-0.5">error</span><p className="text-red-600 text-xs leading-relaxed">{error}</p></div>)}
             </div>
             {currentStep < 5 && (
                 <div className="lg:col-span-1">
                     {renderTripSummary()}
                 </div>
             )}
          </div>
       </div>
       {renderVehicleDetailsPopup()}
    </div>
  );
};

export default BookingDashboard;
